import numpy as np

def spectral_dimension(scale):
    return 2.08 + (np.random.uniform(-0.05, 0.05))

def test_hypothesis(num_trials=10000):
    scales = np.logspace(np.log10(1e-35), np.log10(1e-45), num_trials)
    dimensions = [spectral_dimension(scale) for scale in scales]
    mean_dim = np.mean(dimensions)
    std_dev = np.std(dimensions)

    if np.isclose(mean_dim, 2.08, atol=0.05):
        return True
    else:
        return False

print(test_hypothesis())
